module.exports = {
    name: "loud",
    description: "Make the audio super loud and bass boosted 🔊",
    async execute(message, args) {
        try {
            // Volume multiplier (normal = 1.0)
            const loudLevel = parseFloat(args[0]) || 20; // default 20x louder
            const bassBoost = parseFloat(args[1]) || 5;  // default +5dB bass

            // Store globally so play.js can use it
            global.volumeBoost = Math.min(loudLevel, ); // cap for safety
            global.bassBoost = bassBoost;

            // Build new filter
            global.eqFilter = `volume=${global.volumeBoost},bass=g=${global.bassBoost}`;

            await message.reply(
                `🔊 **LOUD MODE ACTIVATED!**\n> Volume: x${global.volumeBoost}\n> Bass Boost: +${global.bassBoost}dB`
            );
        } catch (err) {
            console.error(err);
            await message.reply("❌ Failed to apply loud mode.");
        }
    }
};
